    else c = abs(p[q.F][q.S].F-p[d][i].F) + abs(p[q.F][q.S].S-p[d][i].S);

    ans = min(ans, solve(k+1, P(d,i))+c);

  }



  return memo[k][q.F][q.S] = ans;

}



